import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Ultrawork 模式：一鍵啟動全部功能 | oh-my-opencode","description":"學習 oh-my-opencode 的 Ultrawork 模式與核心特性，包括 ultrawork 關鍵詞使用方法、啟動行為變化、平行探索機制、強制完成驗證及代理協作等，快速啟動所有進階功能。","frontmatter":{"title":"Ultrawork 模式：一鍵啟動全部功能 | oh-my-opencode","sidebarTitle":"一鍵啟動全部功能","subtitle":"Ultrawork 模式：一鍵啟動全部功能","description":"學習 oh-my-opencode 的 Ultrawork 模式與核心特性，包括 ultrawork 關鍵詞使用方法、啟動行為變化、平行探索機制、強制完成驗證及代理協作等，快速啟動所有進階功能。","tags":["ultrawork","背景任務","代理協作"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"zh-tw/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"zh-tw/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),l={name:"zh-tw/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function d(i,t,s,n,c,p){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="ultrawork-模式-一鍵啟動全部功能" tabindex="-1">Ultrawork 模式：一鍵啟動全部功能 <a class="header-anchor" href="#ultrawork-模式-一鍵啟動全部功能" aria-label="Permalink to &quot;Ultrawork 模式：一鍵啟動全部功能&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>用一句話啟動 oh-my-opencode 的全部進階功能</li><li>讓多個 AI 代理像真實團隊一樣平行工作</li><li>避免手動配置多個代理和背景任務</li><li>理解 Ultrawork 模式的設計哲學和最佳實踐</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能在開發過程中遇到過這些情況：</p><ul><li><strong>功能太多不知道怎麼用</strong>：有 10 個專業代理、背景任務、LSP 工具，但不知道如何快速啟動</li><li><strong>需要手動配置</strong>：每次複雜任務都要手動指定代理、背景併發等配置</li><li><strong>代理協作不高效</strong>：串行呼叫代理，浪費時間和成本</li><li><strong>任務中途卡住</strong>：代理沒有足夠的動力和約束去完成任務</li></ul><p>這些都在影響你發揮 oh-my-opencode 的真正威力。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Ultrawork 模式</strong>是 oh-my-opencode 的「一鍵全員啟動」機制。</p><div class="info custom-block"><p class="custom-block-title">什麼是 Ultrawork 模式？</p><p>Ultrawork 模式是一個關鍵詞觸發的特殊工作模式。當你在提示詞中包含 <code>ultrawork</code> 或縮寫 <code>ulw</code> 時，系統會自動啟動所有進階功能：平行背景任務、深度探索、強制完成、多代理協作等。</p></div><h3 id="設計哲學" tabindex="-1">設計哲學 <a class="header-anchor" href="#設計哲學" aria-label="Permalink to &quot;設計哲學&quot;">​</a></h3><p>Ultrawork 模式基於以下核心原則（來自 <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>）：</p><table tabindex="0"><thead><tr><th>原則</th><th>說明</th></tr></thead><tbody><tr><td><strong>人類干預是失敗信號</strong></td><td>如果你需要不斷修正 AI 的輸出，說明系統設計有問題</td></tr><tr><td><strong>無法區分的程式碼</strong></td><td>AI 寫的程式碼應該和資深工程師寫的沒有區別</td></tr><tr><td><strong>最小化認知負擔</strong></td><td>你只需要說「做什麼」，代理負責「怎麼做」</td></tr><tr><td><strong>可預測、持續、可委託</strong></td><td>代理應該像編譯器一樣穩定可靠</td></tr></tbody></table><h3 id="啟動機制" tabindex="-1">啟動機制 <a class="header-anchor" href="#啟動機制" aria-label="Permalink to &quot;啟動機制&quot;">​</a></h3><p>當系統檢測到 <code>ultrawork</code> 或 <code>ulw</code> 關鍵詞時：</p><ol><li><strong>設定最大精度模式</strong>：<code>message.variant = &quot;max&quot;</code></li><li><strong>顯示 Toast 通知</strong>：「Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.」</li><li><strong>注入完整指令</strong>：向代理注入 200+ 行的 ULTRAWORK 指令，包括： <ul><li>強制 100% 確定才開始實現</li><li>要求平行使用背景任務</li><li>強制使用 Category + Skills 系統</li><li>強制完成驗證（TDD 工作流）</li><li>禁止任何「我做不到」的藉口</li></ul></li></ol><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-觸發-ultrawork-模式" tabindex="-1">第 1 步：觸發 Ultrawork 模式 <a class="header-anchor" href="#第-1-步-觸發-ultrawork-模式" aria-label="Permalink to &quot;第 1 步：觸發 Ultrawork 模式&quot;">​</a></h3><p>在 OpenCode 中輸入包含 <code>ultrawork</code> 或 <code>ulw</code> 關鍵詞的提示詞：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork 開發一個 REST API</span></span></code></pre></div><p>或者更簡潔：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw 新增用戶認證</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>介面彈出 Toast 通知：「Ultrawork Mode Activated」</li><li>代理回覆以「ULTRAWORK MODE ENABLED!」開頭</li></ul><h3 id="第-2-步-觀察代理行為變化" tabindex="-1">第 2 步：觀察代理行為變化 <a class="header-anchor" href="#第-2-步-觀察代理行為變化" aria-label="Permalink to &quot;第 2 步：觀察代理行為變化&quot;">​</a></h3><p>啟動 Ultrawork 模式後，代理會：</p><ol><li><p><strong>平行探索程式碼庫</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;尋找現有 API 模式&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;尋找測試基礎設施&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;尋找認證最佳實踐&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>呼叫 Plan 代理制定工作計劃</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;基於收集的上下文，制定詳細計劃&quot;)</span></span></code></pre></div></li><li><p><strong>使用 Category + Skills 執行任務</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>你應該看到</strong>：</p><ul><li>多個背景任務同時執行</li><li>代理主動呼叫專業代理（Oracle、Librarian、Explore）</li><li>完整的測試計劃和工作分解</li><li>任務持續執行直到 100% 完成</li></ul><h3 id="第-3-步-驗證任務完成" tabindex="-1">第 3 步：驗證任務完成 <a class="header-anchor" href="#第-3-步-驗證任務完成" aria-label="Permalink to &quot;第 3 步：驗證任務完成&quot;">​</a></h3><p>代理完成後會：</p><ol><li><strong>展示驗證證據</strong>：實際執行測試的輸出、手動驗證的描述</li><li><strong>確認所有 TODO 完成</strong>：不會提前宣告完成</li><li><strong>總結工作內容</strong>：列出做了什麼、為什麼這樣做</li></ol><p><strong>你應該看到</strong>：</p><ul><li>明確的測試結果（不是「應該可以」）</li><li>所有問題都已解決</li><li>沒有未完成的 TODO 列表</li></ul><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成上述步驟後，確認：</p><ul><li>[ ] 輸入 <code>ulw</code> 後看到 Toast 通知</li><li>[ ] 代理回覆以「ULTRAWORK MODE ENABLED!」開頭</li><li>[ ] 觀察到平行背景任務執行</li><li>[ ] 代理使用 Category + Skills 系統</li><li>[ ] 任務完成後有驗證證據</li></ul><p>如果任何一項未通過，檢查：</p><ul><li>關鍵詞是否正確拼寫（<code>ultrawork</code> 或 <code>ulw</code>）</li><li>是否在主會話中（背景任務不會觸發模式）</li><li>配置文件是否啟動了相關功能</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場景</th><th>使用 Ultrawork</th><th>普通模式</th></tr></thead><tbody><tr><td><strong>複雜新功能</strong></td><td>✅ 推薦（需要多代理協作）</td><td>❌ 可能不夠高效</td></tr><tr><td><strong>緊急修復</strong></td><td>✅ 推薦（需要快速診斷和探索）</td><td>❌ 可能遺漏上下文</td></tr><tr><td><strong>簡單修改</strong></td><td>❌ 過度（浪費資源）</td><td>✅ 更合適</td></tr><tr><td><strong>快速驗證想法</strong></td><td>❌ 過度</td><td>✅ 更合適</td></tr></tbody></table><p><strong>經驗法則</strong>：</p><ul><li>任務涉及多個模組或系統 → 用 <code>ulw</code></li><li>需要深入研究程式碼庫 → 用 <code>ulw</code></li><li>需要呼叫多個專業代理 → 用 <code>ulw</code></li><li>單檔案小改動 → 不需要 <code>ulw</code></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">注意事項</p><p><strong>1. 不要在每個提示詞中都使用 <code>ulw</code></strong></p><p>Ultrawork 模式會注入大量指令，對於簡單任務來說是過度設計。只有真正需要多代理協作、平行探索、深度分析的複雜任務才使用。</p><p><strong>2. 背景任務不會觸發 Ultrawork 模式</strong></p><p>關鍵詞檢測器會跳過背景會話，避免模式錯誤注入到子代理。Ultrawork 模式只在主會話中有效。</p><p><strong>3. 確保 Provider 配置正確</strong></p><p>Ultrawork 模式依賴多個 AI 模型平行工作。如果某些 Provider 未配置或不可用，代理可能無法呼叫專業代理。</p></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Ultrawork 模式透過關鍵詞觸發，實現了「一句話啟動全部功能」的設計目標：</p><ul><li><strong>簡單易用</strong>：輸入 <code>ulw</code> 即可啟動</li><li><strong>自動協作</strong>：代理自動呼叫其他代理、平行執行背景任務</li><li><strong>強制完成</strong>：完整的驗證機制確保 100% 完成</li><li><strong>零配置</strong>：無需手動設定代理優先順序、併發限制等</li></ul><p>記住：Ultrawork 模式是為了讓代理像真實團隊一樣工作，你只需要表達意圖，代理負責執行。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../platforms/provider-setup/">Provider 配置</a></strong>。</p><p>你會學到：</p><ul><li>如何配置 Anthropic、OpenAI、Google 等多個 Provider</li><li>多模型策略如何自動降級和選擇最優模型</li><li>如何測試 Provider 連接和額度使用</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>Ultrawork 設計哲學</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>關鍵詞檢測器 Hook</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>ULTRAWORK 指令模板</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>關鍵詞檢測邏輯</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>KEYWORD_DETECTORS</code>：關鍵詞檢測器配置，包含 ultrawork、search、analyze 三個模式</li><li><code>CODE_BLOCK_PATTERN</code>：程式碼區塊正規表示式，用於過濾程式碼區塊中的關鍵詞</li><li><code>INLINE_CODE_PATTERN</code>：行內程式碼正規表示式，用於過濾行內程式碼中的關鍵詞</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>createKeywordDetectorHook()</code>：建立關鍵詞檢測器 Hook，監聽 UserPromptSubmit 事件</li><li><code>detectKeywordsWithType()</code>：檢測文字中的關鍵詞並返回類型（ultrawork/search/analyze）</li><li><code>getUltraworkMessage()</code>：生成 ULTRAWORK 模式的完整指令（根據代理類型選擇 Planner 或普通模式）</li><li><code>removeCodeBlocks()</code>：從文字中移除程式碼區塊，避免在程式碼區塊中誤觸發關鍵詞</li></ul><p><strong>業務規則</strong>：</p><table tabindex="0"><thead><tr><th>規則ID</th><th>規則描述</th><th>標記</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>檢測到 &quot;ultrawork&quot; 或 &quot;ulw&quot; 時啟動 Ultrawork 模式</td><td>【事實】</td></tr><tr><td>BR-4.8.4-2</td><td>Ultrawork 模式設定 <code>message.variant = &quot;max&quot;</code></td><td>【事實】</td></tr><tr><td>BR-4.8.4-3</td><td>Ultrawork 模式顯示 Toast 通知：&quot;Ultrawork Mode Activated&quot;</td><td>【事實】</td></tr><tr><td>BR-4.8.4-4</td><td>背景任務會話跳過關鍵詞檢測，避免模式注入</td><td>【事實】</td></tr><tr><td>BR-4.8.4-5</td><td>非主會話只允許 ultrawork 關鍵詞，阻止其他模式注入</td><td>【事實】</td></tr></tbody></table></details>`,54)])])}const g=o(l,[["render",d]]);export{u as __pageData,g as default};
